  conversation: { id: number; title: string; model: string; reasoningEffort: string };
  messages: Message[];
  liveDraft?: any;
  taskRecovery?: TaskRecovery | null;
}> {
  const data = await api<{
    conversation: { id: number; title: string; model: string; reasoningEffort: string };
    messages: Message[];
